############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGlateximage.pl", "parserNumberWithUnits.pl", "WWSC.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
